import{_ as r,o as t,c as l,ai as i}from"./chunks/framework.ampVZV4B.js";const b=JSON.parse('{"title":"NoSQL 数据库","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/database/nosql.md","filePath":"tech-system/database/nosql.md"}'),n={name:"tech-system/database/nosql.md"};function e(o,a,s,h,d,g){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="nosql-数据库" tabindex="-1">NoSQL 数据库 <a class="header-anchor" href="#nosql-数据库" aria-label="Permalink to “NoSQL 数据库”">​</a></h1><p>NoSQL (Not Only SQL) 数据库提供了关系型数据库之外的数据存储方式。通过灵活的数据模型、水平扩展等特性满足大规模数据处理需求。</p><h2 id="nosql-类型" tabindex="-1">NoSQL 类型 <a class="header-anchor" href="#nosql-类型" aria-label="Permalink to “NoSQL 类型”">​</a></h2><h3 id="键值存储" tabindex="-1">键值存储 <a class="header-anchor" href="#键值存储" aria-label="Permalink to “键值存储”">​</a></h3><ul><li><strong>Redis</strong>: 内存数据库、高性能、丰富数据结构</li><li><strong>Memcached</strong>: 缓存系统、简单键值、高并发</li><li><strong>DynamoDB</strong>: AWS 托管、无服务器、按使用计费</li></ul><h3 id="文档数据库" tabindex="-1">文档数据库 <a class="header-anchor" href="#文档数据库" aria-label="Permalink to “文档数据库”">​</a></h3><ul><li><strong>MongoDB</strong>: 文档格式、灵活 Schema、ACID 事务</li><li><strong>CouchDB</strong>: RESTful API、主从复制、冲突解决</li><li><strong>Firebase</strong>: 实时数据库、云托管、移动优先</li></ul><h3 id="列族存储" tabindex="-1">列族存储 <a class="header-anchor" href="#列族存储" aria-label="Permalink to “列族存储”">​</a></h3><ul><li><strong>HBase</strong>: 分布式列存储、大规模数据、Hadoop 生态</li><li><strong>Cassandra</strong>: P2P 架构、高可用、最终一致</li><li><strong>ClickHouse</strong>: OLAP 分析、列式压缩、查询性能</li></ul><h3 id="搜索引擎" tabindex="-1">搜索引擎 <a class="header-anchor" href="#搜索引擎" aria-label="Permalink to “搜索引擎”">​</a></h3><ul><li><strong>Elasticsearch</strong>: 全文搜索、实时分析、近似就绪</li><li><strong>Solr</strong>: 分布式搜索、企业级、灵活配置</li><li><strong>Meilisearch</strong>: 轻量级搜索、接近就绪、用户体验</li></ul><h3 id="图数据库" tabindex="-1">图数据库 <a class="header-anchor" href="#图数据库" aria-label="Permalink to “图数据库”">​</a></h3><ul><li><strong>Neo4j</strong>: 原生图数据库、ACID 事务、查询语言 Cypher</li><li><strong>ArangoDB</strong>: 多模型、图查询、ACID 事务</li><li><strong>TigerGraph</strong>: 大规模图、实时分析、图机器学习</li></ul><h2 id="mongodb" tabindex="-1">MongoDB <a class="header-anchor" href="#mongodb" aria-label="Permalink to “MongoDB”">​</a></h2><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h3><ul><li><strong>文档</strong>: JSON-like 格式、嵌套结构、灵活 Schema</li><li><strong>集合</strong>: 文档的集合、类似表、无强制 Schema</li><li><strong>数据库</strong>: 集合的集合、逻辑隔离</li><li><strong>ObjectId</strong>: 自生成 ID、时间戳、机器标识</li></ul><h3 id="查询操作" tabindex="-1">查询操作 <a class="header-anchor" href="#查询操作" aria-label="Permalink to “查询操作”">​</a></h3><ul><li><strong>CRUD</strong>: Create、Read、Update、Delete</li><li><strong>查询语言</strong>: MongoDB Query Language、灵活条件</li><li><strong>聚合管道</strong>: Pipeline 处理、多阶段转换、丰富操作</li><li><strong>正则表达式</strong>: 文本匹配、模糊查询</li></ul><h3 id="索引与优化" tabindex="-1">索引与优化 <a class="header-anchor" href="#索引与优化" aria-label="Permalink to “索引与优化”">​</a></h3><ul><li><strong>索引类型</strong>: 单字段、复合、数组、文本索引</li><li><strong>写入优化</strong>: Bulk Insert、WriteConc concern</li><li><strong>查询优化</strong>: Explain、执行计划、索引使用</li></ul><h3 id="事务支持" tabindex="-1">事务支持 <a class="header-anchor" href="#事务支持" aria-label="Permalink to “事务支持”">​</a></h3><ul><li><strong>单文档事务</strong>: 原子操作、嵌套字段更新</li><li><strong>多文档事务</strong>: 4.0+ 支持、ACID 保证</li><li><strong>会话</strong>: 客户端会话、事务隔离</li></ul><h2 id="redis" tabindex="-1">Redis <a class="header-anchor" href="#redis" aria-label="Permalink to “Redis”">​</a></h2><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to “数据结构”">​</a></h3><ul><li><strong>String</strong>: 文本、二进制、计数、缓存</li><li><strong>List</strong>: 队列、栈、消息队列、排行榜</li><li><strong>Set</strong>: 去重、集合运算、标签系统</li><li><strong>Hash</strong>: 对象映射、嵌套字段、参数存储</li><li><strong>Sorted Set</strong>: 排序集合、排行榜、去重计数</li></ul><h3 id="持久化" tabindex="-1">持久化 <a class="header-anchor" href="#持久化" aria-label="Permalink to “持久化”">​</a></h3><ul><li><strong>RDB</strong>: 快照持久化、定时保存、恢复快速</li><li><strong>AOF</strong>: 命令日志、精细控制、文件较大</li><li><strong>混合持久化</strong>: 结合两者优点、平衡性能</li></ul><h3 id="高可用架构" tabindex="-1">高可用架构 <a class="header-anchor" href="#高可用架构" aria-label="Permalink to “高可用架构”">​</a></h3><ul><li><strong>主从复制</strong>: 数据同步、读写分离、故障转移</li><li><strong>哨兵模式</strong>: 自动故障转移、监控、故障恢复</li><li><strong>集群模式</strong>: 分片存储、高可用、横向扩展</li></ul><h3 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to “应用场景”">​</a></h3><ul><li><strong>缓存</strong>: 热数据缓存、降低数据库压力</li><li><strong>会话存储</strong>: 分布式会话、跨服务共享</li><li><strong>排行榜</strong>: 实时排行、计数器、排序快速</li><li><strong>消息队列</strong>: 异步处理、任务队列、发布订阅</li></ul><h2 id="数据一致性" tabindex="-1">数据一致性 <a class="header-anchor" href="#数据一致性" aria-label="Permalink to “数据一致性”">​</a></h2><h3 id="cap-理论" tabindex="-1">CAP 理论 <a class="header-anchor" href="#cap-理论" aria-label="Permalink to “CAP 理论”">​</a></h3><ul><li><strong>Consistency (一致性)</strong>: 数据一致、同时更新</li><li><strong>Availability (可用性)</strong>: 系统可用、故障恢复</li><li><strong>Partition Tolerance (分区容错)</strong>: 网络分区、节点故障</li><li><strong>权衡</strong>: 三选二、不同数据库不同选择</li></ul><h3 id="最终一致性" tabindex="-1">最终一致性 <a class="header-anchor" href="#最终一致性" aria-label="Permalink to “最终一致性”">​</a></h3><ul><li><strong>定义</strong>: 短期不一致、最终一致、实用折衷</li><li><strong>同步和异步</strong>: 同步写、异步复制、版本向量</li><li><strong>冲突解决</strong>: 最后写入胜出、应用自定义、向量时钟</li></ul><h2 id="分布式特性" tabindex="-1">分布式特性 <a class="header-anchor" href="#分布式特性" aria-label="Permalink to “分布式特性”">​</a></h2><h3 id="水平扩展" tabindex="-1">水平扩展 <a class="header-anchor" href="#水平扩展" aria-label="Permalink to “水平扩展”">​</a></h3><ul><li><strong>分片</strong>: ShardKey、一致性 Hash、范围分片</li><li><strong>副本</strong>: 数据副本、故障转移、读扩展</li><li><strong>跨地域</strong>: 多数据中心、延迟处理、故障恢复</li></ul><h3 id="分布式事务" tabindex="-1">分布式事务 <a class="header-anchor" href="#分布式事务" aria-label="Permalink to “分布式事务”">​</a></h3><ul><li><strong>两阶段提交</strong>: Prepare、Commit、Abort</li><li><strong>Saga 模式</strong>: 长事务、补偿机制、编程复杂</li><li><strong>最终一致</strong>: 异步确认、重试机制、应用容错</li></ul><h2 id="选型考虑" tabindex="-1">选型考虑 <a class="header-anchor" href="#选型考虑" aria-label="Permalink to “选型考虑”">​</a></h2><h3 id="对比分析" tabindex="-1">对比分析 <a class="header-anchor" href="#对比分析" aria-label="Permalink to “对比分析”">​</a></h3><table tabindex="0"><thead><tr><th>数据库</th><th>一致性</th><th>可用性</th><th>数据模型</th><th>水平扩展</th><th>事务</th><th>适用场景</th></tr></thead><tbody><tr><td>MongoDB</td><td>强</td><td>中</td><td>文档</td><td>⭐⭐⭐⭐</td><td>✅</td><td>CMS、内容管理、快速开发</td></tr><tr><td>Redis</td><td>弱</td><td>强</td><td>键值</td><td>⭐⭐⭐</td><td>限定</td><td>缓存、会话、实时应用</td></tr><tr><td>Cassandra</td><td>弱</td><td>⭐⭐⭐⭐⭐</td><td>列族</td><td>⭐⭐⭐⭐⭐</td><td>❌</td><td>时序数据、大规模日志</td></tr><tr><td>Elasticsearch</td><td>中</td><td>⭐⭐⭐⭐</td><td>文档+索引</td><td>⭐⭐⭐⭐</td><td>有限</td><td>全文搜索、日志分析、指标</td></tr></tbody></table><h3 id="选型原则" tabindex="-1">选型原则 <a class="header-anchor" href="#选型原则" aria-label="Permalink to “选型原则”">​</a></h3><ul><li><strong>数据特性</strong>: 结构化、半结构化、非结构化</li><li><strong>访问模式</strong>: 读密集、写密集、混合负载</li><li><strong>规模</strong>: 数据量、并发量、增长预期</li><li><strong>一致性</strong>: 强一致、最终一致、一致性要求</li><li><strong>运维</strong>: 复杂度、维护成本、学习成本</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h2><h3 id="设计优化" tabindex="-1">设计优化 <a class="header-anchor" href="#设计优化" aria-label="Permalink to “设计优化”">​</a></h3><ul><li><strong>数据模型</strong>: 嵌套与链接平衡、冗余存储</li><li><strong>索引策略</strong>: 查询模式优先、避免过度索引</li><li><strong>避免反模式</strong>: N+1 查询、过度规范化</li></ul><h3 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h3><ul><li><strong>查询优化</strong>: 使用索引、减少扫描、选择性查询</li><li><strong>写入优化</strong>: 批量操作、异步写入、背压处理</li><li><strong>缓存策略</strong>: 读写分离、暖缓存、缓存更新</li></ul><h3 id="可靠性" tabindex="-1">可靠性 <a class="header-anchor" href="#可靠性" aria-label="Permalink to “可靠性”">​</a></h3><ul><li><strong>备份恢复</strong>: 定期备份、恢复验证、灾难恢复</li><li><strong>监控告警</strong>: 关键指标、告警规则、预警机制</li><li><strong>容错设计</strong>: 多副本、故障转移、故障检测</li></ul>',53)])])}const u=r(n,[["render",e]]);export{b as __pageData,u as default};
